/**
 * Authentication context resolution for Telegram users
 * Resolves user identity and company association from Telegram ID
 */

import { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';
import { Tecnico } from '../telegram-types.ts';
import { logger } from '../infra/logger.ts';

export interface AuthContext {
  tecnico: Tecnico | null;
  empresaId: string | null;
  isRegistered: boolean;
  role: 'tecnico' | 'admin_empresa' | 'admin_kraflo' | null;
}

/**
 * Resolve authentication context from Telegram user ID
 */
export async function resolveAuthContext(
  telegramUserId: number,
  supabase: SupabaseClient
): Promise<AuthContext> {
  // Fetch technician record by Telegram ID
  const { data: tecnico, error } = await supabase
    .from('tecnicos')
    .select('*')
    .eq('id_telegram', telegramUserId)
    .maybeSingle();

  if (error) {
    logger.error('Error fetching tecnico', error, { userId: telegramUserId });
    return { tecnico: null, empresaId: null, isRegistered: false, role: null };
  }

  if (!tecnico) {
    return { tecnico: null, empresaId: null, isRegistered: false, role: null };
  }

  // Check for admin roles via profiles table
  const { data: profile } = await supabase
    .from('profiles')
    .select('id')
    .eq('id_telegram', telegramUserId)
    .maybeSingle();

  let role: AuthContext['role'] = 'tecnico';

  if (profile?.id) {
    // Check admin_kraflo role
    const { data: isAdminKraflo } = await supabase.rpc('is_admin_kraflo', {
      _user_id: profile.id,
    });

    if (isAdminKraflo) {
      role = 'admin_kraflo';
    } else {
      // Check admin_empresa role
      const { data: hasAdminRole } = await supabase.rpc('has_role', {
        _user_id: profile.id,
        _role: 'admin_empresa',
      });
      if (hasAdminRole) {
        role = 'admin_empresa';
      }
    }
  }

  return {
    tecnico,
    empresaId: tecnico.empresa_id,
    isRegistered: true,
    role,
  };
}

/**
 * Quick check if a user is registered as a technician
 */
export async function isRegistered(
  telegramUserId: number,
  supabase: SupabaseClient
): Promise<Tecnico | null> {
  const { data: tecnico } = await supabase
    .from('tecnicos')
    .select('*')
    .eq('id_telegram', telegramUserId)
    .maybeSingle();

  return tecnico || null;
}

/**
 * Role-based access control guards for bot commands
 */

import { AuthContext } from './auth-context.ts';
import { sendMessage } from '../services/telegram-service.ts';
import { mainMenuKeyboard } from '../infra/config.ts';

/**
 * Ensure user is registered as a technician
 */
export async function ensureRegistered(
  chatId: number,
  userId: number,
  auth: AuthContext
): Promise<boolean> {
  if (!auth.isRegistered || !auth.tecnico) {
    await sendMessage(
      chatId,
      `❌ Você precisa estar cadastrado para usar esta função.\n\n` +
      `📝 Cadastre-se pelo sistema web:\nhttps://kraflo.lovable.app/auth\n\n` +
      `🆔 Seu ID Telegram: \`${userId}\``,
      undefined,
      'Markdown'
    );
    return false;
  }
  return true;
}

/**
 * Ensure user has admin_empresa or admin_kraflo role
 */
export async function ensureAdmin(
  chatId: number,
  auth: AuthContext
): Promise<boolean> {
  if (auth.role !== 'admin_empresa' && auth.role !== 'admin_kraflo') {
    await sendMessage(
      chatId,
      '❌ Acesso negado. Apenas administradores podem executar esta ação.',
      mainMenuKeyboard
    );
    return false;
  }
  return true;
}

/**
 * Ensure user is admin_kraflo (super admin)
 */
export async function ensureAdminKraflo(
  chatId: number,
  auth: AuthContext
): Promise<boolean> {
  if (auth.role !== 'admin_kraflo') {
    await sendMessage(
      chatId,
      '❌ Acesso negado. Apenas administradores Kraflo podem executar esta ação.',
      mainMenuKeyboard
    );
    return false;
  }
  return true;
}

/**
 * Check if user can access OS from a specific company
 */
export function canAccessCompanyData(
  auth: AuthContext,
  targetEmpresaId: string
): boolean {
  // Admin Kraflo can access all companies
  if (auth.role === 'admin_kraflo') return true;

  // Other users can only access their own company
  return auth.empresaId === targetEmpresaId;
}

