/**
 * Serviço de detecção de reincidência para alertar técnicos
 */

import { SupabaseClient } from "https://esm.sh/@supabase/supabase-js@2.49.1";

export interface ReincidenciaCheck {
  encontrou: boolean;
  total_recentes: number;
  dias_limite?: number;
  ultima_os?: {
    id: number;
    descricao_problema: string | null;
    diagnostico_solucao: string | null;
    data_fechamento: string;
    tecnico_id: number;
    tecnico_nome: string | null;
    dias_desde_fechamento: number;
  };
}

/**
 * Verifica se existe histórico recente para a TAG especificada
 */
export async function checkReincidencia(
  supabase: SupabaseClient,
  empresaId: string,
  tag: string,
  diasLimite = 60
): Promise<ReincidenciaCheck> {
  const { data, error } = await supabase.rpc("fn_check_reincidencia", {
    p_empresa_id: empresaId,
    p_tag: tag,
    p_dias_limite: diasLimite,
  });

  if (error) {
    console.error("Erro ao verificar reincidência:", error);
    return { encontrou: false, total_recentes: 0 };
  }

  return data as ReincidenciaCheck;
}

/**
 * Formata mensagem de alerta de reincidência para o Telegram
 */
export function formatReincidenciaAlert(check: ReincidenciaCheck, tag: string): string {
  if (!check.encontrou || !check.ultima_os) {
    return "";
  }

  const os = check.ultima_os;
  const diasDesde = Math.round(os.dias_desde_fechamento);

  let alerta = `⚠️ *ATENÇÃO - Histórico Detectado!*\n\n`;
  alerta += `A máquina *${tag}* teve ${check.total_recentes} `;
  alerta += `ocorrência${check.total_recentes > 1 ? "s" : ""} nos últimos ${check.dias_limite} dias.\n\n`;

  if (os.diagnostico_solucao) {
    alerta += `📋 *Última solução:* ${os.diagnostico_solucao.substring(0, 150)}${os.diagnostico_solucao.length > 150 ? "..." : ""}\n`;
  }

  if (os.tecnico_nome) {
    alerta += `👤 *Técnico:* ${os.tecnico_nome}\n`;
  }

  alerta += `⏱️ *Há:* ${diasDesde} dia${diasDesde !== 1 ? "s" : ""}\n\n`;

  if (diasDesde < 7) {
    alerta += `🔴 *Reincidência Crítica!* A solução anterior durou apenas ${diasDesde} dias. `;
    alerta += `Verifique se a causa raiz foi tratada.\n\n`;
  } else if (diasDesde < 30) {
    alerta += `🟠 *Reincidência Detectada.* Considere revisar a solução anterior.\n\n`;
  }

  alerta += `Deseja prosseguir com a abertura?`;

  return alerta;
}

/**
 * Report generation service
 */

import { SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';
import { OrdemDeServico } from '../telegram-types.ts';
import { logger } from '../infra/logger.ts';

export interface ReportStats {
  total: number;
  abertas: number;
  fechadas: number;
  corretivas: number;
  preventivas: number;
  urgentes: number;
  avgResolutionHours?: number;
}

export interface EquipmentStats {
  name: string;
  count: number;
}

/**
 * Get general report stats for a company
 */
export async function getGeneralStats(
  supabase: SupabaseClient,
  empresaId: string
): Promise<ReportStats | null> {
  const { data: allOS, error } = await supabase
    .from('ordens_de_servico')
    .select('*')
    .eq('empresa_id', empresaId);

  if (error || !allOS) {
    logger.error('Error fetching general stats', error, { empresaId });
    return null;
  }

  return {
    total: allOS.length,
    abertas: allOS.filter((os: OrdemDeServico) => os.status_os === 'Aberta' || os.status_os === 'Em manutenção').length,
    fechadas: allOS.filter((os: OrdemDeServico) => os.status_os === 'Fechada' || os.status_os === 'Liberado para produção' || os.status_os === 'Não liberado').length,
    corretivas: allOS.filter((os: OrdemDeServico) => os.tipo_manutencao === 'Corretiva').length,
    preventivas: allOS.filter((os: OrdemDeServico) => os.tipo_manutencao === 'Preventiva').length,
    urgentes: allOS.filter((os: OrdemDeServico) => os.prioridade === 'Urgente').length,
  };
}

/**
 * Get personal stats for a technician
 */
export async function getPersonalStats(
  supabase: SupabaseClient,
  tecnicoId: number
): Promise<ReportStats | null> {
  const { data: myOS, error } = await supabase
    .from('ordens_de_servico')
    .select('*')
    .eq('tecnico_id', tecnicoId);

  if (error || !myOS) {
    logger.error('Error fetching personal stats', error, { tecnicoId });
    return null;
  }

  const total = myOS.length;
  const abertas = myOS.filter((os: OrdemDeServico) => os.status_os === 'Aberta' || os.status_os === 'Em manutenção').length;
  const fechadas = total - abertas;

  // Calculate average resolution time
  const closedWithTime = myOS.filter((os: OrdemDeServico) => os.data_fechamento);
  let avgResolutionHours: number | undefined;

  if (closedWithTime.length > 0) {
    const totalHours = closedWithTime.reduce((acc: number, os: OrdemDeServico) => {
      const open = new Date(os.data_abertura).getTime();
      const close = new Date(os.data_fechamento!).getTime();
      return acc + (close - open) / (1000 * 60 * 60);
    }, 0);
    avgResolutionHours = Math.round(totalHours / closedWithTime.length);
  }

  return {
    total,
    abertas,
    fechadas,
    corretivas: myOS.filter((os: OrdemDeServico) => os.tipo_manutencao === 'Corretiva').length,
    preventivas: myOS.filter((os: OrdemDeServico) => os.tipo_manutencao === 'Preventiva').length,
    urgentes: myOS.filter((os: OrdemDeServico) => os.prioridade === 'Urgente').length,
    avgResolutionHours,
  };
}

